import { useState, createContext, useContext, useEffect } from "react";

const OrderContext = createContext();

export const OrderProvider = ({ children }) => {
  // Load initial state from localStorage
  const initialOrder = JSON.parse(localStorage.getItem("order")) || {};
  const [order, setOrder] = useState(initialOrder);
  const [menu, setMenu] = useState([]);

  const addToOrder = (productID, quantity) => {
    if (!menu) return;

    const product = menu.find(item => item.item === productID);
    if (!product) return;

    setOrder(prevOrder => {
      const currentQuantity = prevOrder[productID]?.quantity || 0;
      const newQuantity = currentQuantity + quantity;

      if (newQuantity <= 0) {
        const { [productID]: _, ...rest } = prevOrder;
        return rest;
      } else {
        return {
          ...prevOrder,
          [productID]: {
            ...product,
            quantity: newQuantity,
          },
        };
      }
    });
  };

  const removeFromOrder = (productID) => {
    setOrder(prevOrder => {
      const { [productID]: _, ...rest } = prevOrder;
      return rest;
    });
  };

  // Sync `order` with `localStorage`
  useEffect(() => {
    localStorage.setItem("order", JSON.stringify(order));
  }, [order,addToOrder]);

  useEffect(() => {
    console.log("Menu:", menu);
  }, [menu]);

  return (
    <OrderContext.Provider value={{ order, addToOrder, menu, setMenu, removeFromOrder }}>
      {children}
    </OrderContext.Provider>
  );
};

export const useOrderContext = () => useContext(OrderContext);
